import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

const API_BASE = "http://localhost:7000/api";

function StatCard({ title, value, icon, accent = "#e9f2ff" }) {
  return (
    <div className="stat-card">
      <div className="stat-icon" style={{ background: accent }}>
        <span className="emoji">{icon}</span>
      </div>
      <div className="stat-details">
        <div className="stat-value">{value}</div>
        <div className="stat-title">{title}</div>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const token = useMemo(() => localStorage.getItem("token") || "", []);
  const auth = token ? { Authorization: "Bearer " + token } : undefined;

  const [stats, setStats] = useState({
    users: 0,
    brokers: 0,
    transactions: 0,
    revenue: 0,
  });
  const [recent, setRecent] = useState([]);
  const [prices, setPrices] = useState([]);
  const [categories, setCategories] = useState([]);

  const [loadingStats, setLoadingStats] = useState(true);
  const [loadingRecent, setLoadingRecent] = useState(true);
  const [loadingGraph, setLoadingGraph] = useState(true);
  const [errorMsg, setErrorMsg] = useState("");

  // Filters
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [startDate, setStartDate] = useState(""); // yyyy-mm-dd
  const [endDate, setEndDate] = useState("");

  // Fetch stats, recent, prices, categories
  useEffect(() => {
    const doFetch = async () => {
      try {
        setLoadingStats(true);
        const s = await axios.get(`${API_BASE}/admin/stats`, { headers: auth });
        setStats(s.data || {});
      } catch (e) {
        setErrorMsg("Failed to load stats");
      } finally {
        setLoadingStats(false);
      }

      try {
        setLoadingRecent(true);
        const r = await axios.get(`${API_BASE}/admin/recent`, { headers: auth });
        setRecent(Array.isArray(r.data) ? r.data : []);
      } catch {
        setRecent([]);
      } finally {
        setLoadingRecent(false);
      }

      try {
        setLoadingGraph(true);
        const [pRes, cRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`, { headers: auth }),
          axios.get(`${API_BASE}/categories`, { headers: auth }),
        ]);
        setPrices(pRes.data?.data || []);
        setCategories(cRes.data?.categories || []);
      } catch (e) {
        setPrices([]);
        setCategories([]);
      } finally {
        setLoadingGraph(false);
      }
    };

    doFetch();

    // Auto refresh recent activity every 10s
    const id = setInterval(async () => {
      try {
        const r = await axios.get(`${API_BASE}/admin/recent`, { headers: auth });
        setRecent(Array.isArray(r.data) ? r.data : []);
      } catch {}
    }, 10000);

    return () => clearInterval(id);
  }, [auth]);

  // Prepare graph data (date-wise)
  const graphData = useMemo(() => {
    // Filter source: prices
    let filtered = [...prices];

    if (selectedProduct) {
      filtered = filtered.filter((x) => (x.name || "").trim() === selectedProduct.trim());
    }
    if (selectedCategory) {
      filtered = filtered.filter((x) => (x.category?.name || "") === selectedCategory);
    }
    if (startDate && endDate) {
      const s = new Date(startDate);
      const e = new Date(endDate);
      filtered = filtered.filter((x) => {
        const date = new Date(x.validTill || x.createdAt);
        return date >= s && date <= e;
      });
    }

    // Group by date (validTill or createdAt)
    const grouped = {};
    filtered.forEach((item) => {
      const dateKey = new Date(item.validTill || item.createdAt).toLocaleDateString("en-IN", {
        day: "2-digit",
        month: "short",
        year: "numeric",
      });
      if (!grouped[dateKey]) grouped[dateKey] = [];
      grouped[dateKey].push(item);
    });

    const labels = Object.keys(grouped);
    const avgBase = labels.map((d) => {
      const arr = grouped[d];
      const total = arr.reduce((sum, i) => sum + (Number(i.basePrice) || 0), 0);
      return Number((total / arr.length).toFixed(2));
    });
    const avgDiff = labels.map((d) => {
      const arr = grouped[d];
      const total = arr.reduce((sum, i) => sum + (Number(i.difference) || 0), 0);
      return Number((total / arr.length).toFixed(2));
    });
    const count = labels.map((d) => grouped[d].length);

    return {
      labels,
      datasets: [
        {
          label: "Avg Base Price (₹)",
          data: avgBase,
          backgroundColor: "rgba(0, 123, 255, 0.65)",
          borderRadius: 8,
          order: 1,
        },
        {
          label: "Avg Difference (₹)",
          data: avgDiff,
          backgroundColor: "rgba(255, 193, 7, 0.75)",
          borderRadius: 8,
          order: 2,
        },
        {
          label: "Total Products (count)",
          data: count,
          backgroundColor: "rgba(40, 167, 69, 0.6)",
          borderRadius: 8,
          order: 0,
        },
      ],
    };
  }, [prices, selectedProduct, selectedCategory, startDate, endDate]);

  const productOptions = useMemo(() => {
    const set = new Set(prices.map((p) => p.name).filter(Boolean));
    return Array.from(set);
  }, [prices]);

  // Export current graph snapshot CSV
  const exportGraphCSV = () => {
    if (!graphData?.labels?.length) return;
    const header = "Date,Avg Base Price,Avg Difference,Total Products\n";
    const rows = graphData.labels
      .map((label, idx) => {
        const a = graphData.datasets[0]?.data[idx] ?? "";
        const b = graphData.datasets[1]?.data[idx] ?? "";
        const c = graphData.datasets[2]?.data[idx] ?? "";
        return `${label},${a},${b},${c}`;
      })
      .join("\n");

    const blob = new Blob([header + rows], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `price_analytics_${Date.now()}.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="dash-wrap">
      <div className="dash-header">
        <h2>📊 Admin Dashboard</h2>
        <p>Overview of users, brokers, transactions & price analytics</p>
      </div>

      {/* Stats */}
      <div className="stats-grid">
        <div className={`card-anim ${loadingStats ? "skeleton" : ""}`}>
          <StatCard title="Total Users" value={stats?.users ?? 0} icon="👥" accent="#e7f1ff" />
        </div>
        <div className={`card-anim ${loadingStats ? "skeleton" : ""}`}>
          <StatCard title="Total Brokers" value={stats?.brokers ?? 0} icon="💼" accent="#fff3cd" />
        </div>
        <div className={`card-anim ${loadingStats ? "skeleton" : ""}`}>
          <StatCard title="Transactions" value={stats?.transactions ?? 0} icon="🔁" accent="#d4edda" />
        </div>
        <div className={`card-anim ${loadingStats ? "skeleton" : ""}`}>
          <StatCard title="Revenue" value={`₹${stats?.revenue ?? 0}K`} icon="💰" accent="#f8d7da" />
        </div>
      </div>

      {/* Filters */}
      <div className="filters card-anim">
        <div className="filter-item">
          <label>🧃 Product</label>
          <select value={selectedProduct} onChange={(e) => setSelectedProduct(e.target.value)}>
            <option value="">All</option>
            {productOptions.map((p) => (
              <option key={p} value={p}>
                {p}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-item">
          <label>🗂️ Category</label>
          <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
            <option value="">All</option>
            {categories.map((c) => (
              <option key={c._id} value={c.name}>
                {c.name}
              </option>
            ))}
          </select>
        </div>

        <div className="filter-item">
          <label>📅 From</label>
          <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
        </div>

        <div className="filter-item">
          <label>➡️ To</label>
          <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
        </div>

        <div className="filter-actions">
          <button className="btn primary" onClick={() => { /* chart auto updates via deps */ }}>
            🔄 Apply
          </button>
          <button className="btn ghost" onClick={exportGraphCSV}>📤 Export CSV</button>
        </div>
      </div>

      {/* Analytics */}
      <div className="panel card-anim">
        <div className="panel-header">
          <h4>📈 Price History (Date-wise)</h4>
          <span className="hint">Avg base price, avg difference & total items per day</span>
        </div>

        <div className="chart-area">
          {loadingGraph ? (
            <div className="loading">Loading chart…</div>
          ) : graphData?.labels?.length ? (
            <Bar
              data={graphData}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: { position: "bottom", labels: { boxWidth: 14 } },
                  tooltip: {
                    callbacks: {
                      label: (ctx) => {
                        const label = ctx.dataset.label || "";
                        const y = ctx.parsed.y;
                        if (label.includes("count")) return `${label}: ${y}`;
                        return `${label}: ₹${Number(y).toLocaleString("en-IN")}`;
                      },
                    },
                  },
                  title: { display: false },
                },
                scales: {
                  x: { ticks: { color: "#40464f" }, title: { display: true, text: "Date" } },
                  y: {
                    beginAtZero: true,
                    ticks: { color: "#40464f" },
                    title: { display: true, text: "₹ / Count" },
                  },
                },
              }}
            />
          ) : (
            <div className="no-data">No data for selected filters.</div>
          )}
        </div>
      </div>

      {/* Recent Activity */}
      <div className="panel card-anim">
        <div className="panel-header">
          <h4>🕓 Recent Activity</h4>
          <span className="hint">Auto-refreshes every 10 seconds</span>
        </div>

        <div className="table-wrap">
          <table className="nice-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>User</th>
                <th>Action</th>
                <th>Entity</th>
                <th>Date</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {loadingRecent ? (
                [...Array(5)].map((_, i) => (
                  <tr key={i} className="row-skeleton">
                    <td colSpan={6} />
                  </tr>
                ))
              ) : recent?.length ? (
                recent.map((r) => (
                  <tr key={r.id}>
                    <td>{r.id}</td>
                    <td>{r.user}</td>
                    <td>{r.action}</td>
                    <td>{r.entity || "—"}</td>
                    <td>
                      {r.date
                        ? new Date(r.date).toLocaleString("en-IN", {
                            day: "2-digit",
                            month: "short",
                            year: "numeric",
                            hour: "2-digit",
                            minute: "2-digit",
                          })
                        : "—"}
                    </td>
                    <td>
                      <span className={`badge ${r.status === "Success" ? "ok" : "err"}`}>
                        {r.status || "Unknown"}
                      </span>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={6} className="no-data">
                    No activity found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {!!errorMsg && <div className="toast err">{errorMsg}</div>}
    </div>
  );
}
